import math

def is_prime(k: int) -> bool:
    """Checks if an integer k is a prime number."""
    if k < 2:
        return False
    if k == 2:
        return True
    if k % 2 == 0:
        return False
    # Check divisibility up to sqrt(k)
    for i in range(3, int(math.sqrt(k)) + 1, 2):
        if k % i == 0:
            return False
    return True

def reverse_integer(n: int) -> int:
    """Reverses the digits of an integer n."""
    return int(str(n)[::-1])

def solve(n: int) -> int:
    """
    Calculates the sum of all prime numbers between min(n, r) and max(n, r) (inclusive),
    where r is the reverse of n.
    """
    r = reverse_integer(n)

    start = min(n, r)
    end = max(n, r)

    prime_sum = 0
    for i in range(start, end + 1):
        if is_prime(i):
            prime_sum += i

    return prime_sum
